function parseDuration(str) {
  const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };

  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  // ms must precede m in the alternation so "500ms" isn't split into "500m" + "s"
  const TOKEN = /(\d+)(ms|s|m|h|d)/g;
  let total = 0;
  let lastIndex = 0;
  let match;

  while ((match = TOKEN.exec(str)) !== null) {
    if (match.index !== lastIndex) {
      throw new Error(`parseDuration: unparseable input "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    lastIndex = TOKEN.lastIndex;
  }

  if (lastIndex === 0 || lastIndex !== str.length) {
    throw new Error(`parseDuration: unparseable input "${str}"`);
  }

  return total;
}

